  mealType: MealType;
  menuVeg?: string;
  menuNonVeg?: string;
  cutoffAt: string;
  capacity: number;
  active: boolean;
}

export interface Booking {
  id: string;
  employeeId: string;
  scheduleId: string;
  date: string;
  mealType: MealType;
  dietType: DietType;
  status: BookingStatus;
  bookedAt: string;
  cancelledAt?: string;
  servedAt?: string;
}

