  date: string;
  mealType: MealType;
  registered: number;
  served: number;
  noShow: number;
  cancelled: number;
  vegRegistered: number;
  nonVegRegistered: number;
  vegServed: number;
  nonVegServed: number;
}

export interface ServeEmployeeInfo {
  name: string;
  employeeCode: string;
  dietType: DietType;
  mealType: MealType;
  dietLabel: string;
}

