export interface BookingWithEmployee extends Booking {
  employee: Pick<Employee, "employeeCode" | "name" | "email" | "department">;
}

export const adminService = {
  async listBookingsWithEmployees(date: string): Promise<BookingWithEmployee[]> {
    const bookings = await bookingRepo.findByDate(date);
    const result: BookingWithEmployee[] = [];

    for (const booking of bookings) {
      const employee = await employeeRepo.findById(booking.employeeId);
      result.push({
        ...booking,
        employee: employee
          ? {
              employeeCode: employee.employeeCode,
              name: employee.name,
              email: employee.email,
              department: employee.department,
            }
          : {
              employeeCode: "—",
              name: "Unknown",
              email: "—",
              department: "—",
            },
      });
    }

    return result.sort((a, b) => a.mealType.localeCompare(b.mealType));
  },
};

import { v4 as uuid } from "uuid";
import { feedbackRepo } from "../repositories/memory";
import type { DietType, MealType } from "@office-meal/shared";
import { AppError } from "../domain/errors";

export const feedbackService = {
  async submit(input: {
    employeeId: string;
    date: string;
    mealType: MealType;
    dietType: DietType;
    rating: number;
    tags?: string[];
    comment?: string;
    facilityNotes?: string;
  }) {
    const feedback = {
      id: uuid(),
      employeeId: input.employeeId,
      date: input.date,
      mealType: input.mealType,
      dietType: input.dietType,
      rating: input.rating,
      tags: input.tags ?? [],
      comment: input.comment,
      facilityNotes: input.facilityNotes,
      createdAt: new Date().toISOString(),
    };
    await feedbackRepo.save(feedback);
    return feedback;
  },

  async listMine(employeeId: string) {
    return feedbackRepo.findByEmployee(employeeId);
  },

  async update(
    id: string,
    employeeId: string,
    input: {
      rating: number;
      tags?: string[];
      comment?: string;
      facilityNotes?: string;
    }
  ) {
    const existing = await feedbackRepo.findById(id);
    if (!existing || existing.employeeId !== employeeId) {
      throw new AppError("Feedback not found", 404);
    }
    const updated = {
      ...existing,
      rating: input.rating,
      tags: input.tags ?? existing.tags,
      comment: input.comment,
      facilityNotes: input.facilityNotes,
      updatedAt: new Date().toISOString(),
    };
    await feedbackRepo.save(updated);
    return updated;
  },

  async listByDate(date: string) {
    return feedbackRepo.findByDate(date);
  },
};

