import { Html5Qrcode } from "html5-qrcode";

const SCANNER_ID = "office-meal-qr-scanner";

interface QrScannerProps {
  onScan: (token: string) => void;
  onError?: (message: string) => void;
}

export function QrScanner({ onScan, onError }: QrScannerProps) {
  const scannerRef = useRef<Html5Qrcode | null>(null);
  const [active, setActive] = useState(false);
  const [cameraError, setCameraError] = useState("");
  const lastScanRef = useRef("");

  useEffect(() => {
    return () => {
      void stopScanner();
    };
  }, []);

  async function stopScanner() {
    const scanner = scannerRef.current;
    if (!scanner) return;
    try {
      if (scanner.isScanning) {
        await scanner.stop();
      }
      scanner.clear();
    } catch {
      /* ignore cleanup errors */
    }
    scannerRef.current = null;
    setActive(false);
  }

  async function startScanner() {
    setCameraError("");
    await stopScanner();

    const scanner = new Html5Qrcode(SCANNER_ID);
    scannerRef.current = scanner;

    try {
      await scanner.start(
        { facingMode: "environment" },
        { fps: 10, qrbox: { width: 250, height: 250 } },
        (decoded) => {
          const token = decoded.trim();
          if (!token || token === lastScanRef.current) return;
          lastScanRef.current = token;
          onScan(token);
        },
        () => {
          /* scan attempt — no match yet */
        }
      );
      setActive(true);
    } catch (err) {
      const msg =
        err instanceof Error
          ? err.message
          : "Camera access denied or unavailable";
      setCameraError(msg);
      onError?.(msg);
      await stopScanner();
    }
  }

  return (
    <div className="qr-scanner-wrap">
      <div id={SCANNER_ID} className="qr-scanner-view" />
      {cameraError && (
        <p className="error" style={{ fontSize: "0.85rem" }}>
          {cameraError}. Use manual paste below or allow camera permissio

import { v4 as uuid } from "uuid";
import type { MealSchedule, MealType } from "@office-meal/shared";
import { AppError } from "../domain/errors";
import { scheduleRepo } from "../repositories/memory";

export const scheduleService = {
  async listByDate(date: string) {
    return scheduleRepo.listByDate(date);
  },

  async upsert(input: {
    date: string;
    mealType: MealType;
    menuVeg?: string;
    menuNonVeg?: string;
    cutoffAt: string;
    capacity: number;
    active?: boolean;
  }) {
    const existing = await scheduleRepo.findByDateAndMeal(
      input.date,
      input.mealType
    );

    if (existing) {
      const updated: MealSchedule = {
        ...existing,
        menuVeg: input.menuVeg ?? existing.menuVeg,
        menuNonVeg: input.menuNonVeg ?? existing.menuNonVeg,
        cutoffAt: input.cutoffAt,
        capacity: input.capacity,
        active: input.active ?? existing.active,
      };
      await scheduleRepo.save(updated);
      return updated;
    }

    const schedule: MealSchedule = {
      id: uuid(),
      date: input.date,
      mealType: input.mealType,
      menuVeg: input.menuVeg,
      menuNonVeg: input.menuNonVeg,
      cutoffAt: input.cutoffAt,
      capacity: input.capacity,
      active: input.active ?? true,
    };
    await scheduleRepo.save(schedule);
    return schedule;
  },

  async remove(id: string) {
    const schedule = await scheduleRepo.findById(id);
    if (!schedule) {
      throw new AppError("Schedule not found", 404);
    }
    await scheduleRepo.save({ ...schedule, active: false });
    return { id, deactivated: true };
  },
};

