import { v4 as uuid } from "uuid";
import type { MealSchedule, MealType } from "@office-meal/shared";
import { AppError } from "../domain/errors";
import { scheduleRepo } from "../repositories/memory";

export const scheduleService = {
  async listByDate(date: string) {
    return scheduleRepo.listByDate(date);
  },

  async upsert(input: {
    date: string;
    mealType: MealType;
    menuVeg?: string;
    menuNonVeg?: string;
    cutoffAt: string;
    capacity: number;
    active?: boolean;
  }) {
    const existing = await scheduleRepo.findByDateAndMeal(
      input.date,
      input.mealType
    );

    if (existing) {
      const updated: MealSchedule = {
        ...existing,
        menuVeg: input.menuVeg !== undefined ? input.menuVeg : existing.menuVeg,
        menuNonVeg:
          input.menuNonVeg !== undefined ? input.menuNonVeg : existing.menuNonVeg,
        cutoffAt: input.cutoffAt,
        capacity: input.capacity,
        active: input.active !== undefined ? input.active : true,
      };
      await scheduleRepo.save(updated);
      return updated;
    }

    const schedule: MealSchedule = {
      id: uuid(),
      date: input.date,
      mealType: input.mealType,
      menuVeg: input.menuVeg,
      menuNonVeg: input.menuNonVeg,
      cutoffAt: input.cutoffAt,
      capacity: input.capacity,
      active: input.active ?? true,
    };
    await scheduleRepo.save(schedule);
    return schedule;
  },

  async remove(id: string) {
    const schedule = await scheduleRepo.findById(id);
    if (!schedule) {
      throw new AppError("Schedule not found", 404);
    }
    await scheduleRepo.save({ ...schedule, active: false });
    return { id, deactivated: true };
  },
};

