  Write-Host "[OK] Git repo exists" -ForegroundColor Green
  git status -sb
} else {
  Write-Host "[INFO] No git repo yet — run:" -ForegroundColor Yellow
  Write-Host "  git init"
  Write-Host "  git add ."
  Write-Host "  git commit -m `"Office meal app`""
